script.text:
      /* <flatten type="Javascript"> */
function onLoadClosingEntryForm(f) {
  if (f._action != 'View')  {
    onChange$ClosingEntryItemChecked(f);
    if (!(f.getItem('loai_kc').value == 4)) {onClick$ClosingEntryItemChecked(f);}
  }
}
function onClosingEntryItemChecked(o) {
  var f = o.parentForm, name = o.field.Name, v = (o.value == 4);
  switch (name) {
    case 'loai_kc':
      onChange$ClosingEntryItemChecked(f);
      if (!v) onClick$ClosingEntryItemChecked(f);
      break;
    default:
      onClick$ClosingEntryItemChecked(f);
      break;
  }
}
function onChange$ClosingEntryItemChecked(f) {f.getItem('kc_ct_yn').disabled = f.getItem('kc_vv_yn').disabled = f.getItem('kc_kh_yn').disabled = f.getItem('kc_sp_yn').disabled = f.getItem('kc_bp_yn').disabled = f.getItem('kc_lsx_yn').disabled = f.getItem('kc_hd_yn').disabled = f.getItem('kc_ku_yn').disabled = f.getItem('kc_phi_yn').disabled = f.getItem('kc_td1_yn').disabled = f.getItem('kc_td2_yn').disabled = f.getItem('kc_td3_yn').disabled = (f.getItem('loai_kc').value == 4);}
function onClick$ClosingEntryItemChecked(f) {f.getItem('kc_ct_yn').disabled = !(f.getItem('kc_vv_yn').checked || f.getItem('kc_kh_yn').checked || f.getItem('kc_sp_yn').checked || f.getItem('kc_bp_yn').checked || f.getItem('kc_lsx_yn').checked || f.getItem('kc_hd_yn').checked || f.getItem('kc_ku_yn').checked || f.getItem('kc_phi_yn').checked || f.getItem('kc_td1_yn').checked || f.getItem('kc_td2_yn').checked || f.getItem('kc_td3_yn').checked);}
/* </flatten> */
